import Foundation
import XCTest

@testable import SmeltRuntime

final class SmeltPointSelectorTests: XCTestCase {
    func testPinnedNumPyCandidatesAndFPSMatchSourceFixture() throws {
        let points = pointFixture()
        let mesh = try SmeltPointSelector.select(
            pointNormals: points,
            projection: .mesh
        )
        let condition = try SmeltPointSelector.select(
            pointNormals: points,
            projection: .condition
        )
        XCTAssertEqual(mesh.sourceIndices, decode(meshExpectedBase64, count: 512))
        XCTAssertEqual(
            condition.sourceIndices,
            decode(conditionExpectedBase64, count: 384)
        )
        XCTAssertEqual(mesh.pointNormals.count, 512 * 6)
        XCTAssertEqual(condition.pointNormals.count, 384 * 6)
        for (selectedPosition, sourceIndex) in mesh.sourceIndices.enumerated() {
            XCTAssertEqual(
                Array(mesh.pointNormals[(selectedPosition * 6)..<(selectedPosition * 6 + 6)]),
                Array(points[(sourceIndex * 6)..<(sourceIndex * 6 + 6)])
            )
        }
    }

    func testRejectsShapeAndNonFiniteInput() throws {
        XCTAssertThrowsError(
            try SmeltPointSelector.select(pointNormals: [], projection: .mesh)
        )
        var values = pointFixture()
        values[17] = .nan
        XCTAssertThrowsError(
            try SmeltPointSelector.select(pointNormals: values, projection: .condition)
        )
    }

    private func pointFixture() -> [Float] {
        var values = [Float](repeating: 0, count: 54_000 * 6)
        for index in 0..<54_000 {
            values[index * 6] = Float((index * 37) % 4_096 - 2_048) / 2_048
            values[index * 6 + 1] = Float((index * 109) % 8_192 - 4_096) / 4_096
            values[index * 6 + 2] = Float((index * 251) % 16_384 - 8_192) / 8_192
            values[index * 6 + 3] = Float((index * 13) % 256 - 128) / 128
            values[index * 6 + 4] = Float((index * 29) % 256 - 128) / 128
            values[index * 6 + 5] = Float((index * 61) % 256 - 128) / 128
        }
        return values
    }

    private func decode(_ encoded: String, count: Int) -> [Int] {
        let data = Data(base64Encoded: encoded, options: .ignoreUnknownCharacters)
        XCTAssertEqual(data?.count, count * 4)
        return data?.withUnsafeBytes { bytes in
            (0..<count).map { index in
                Int(
                    bytes.loadUnaligned(
                        fromByteOffset: index * 4,
                        as: UInt32.self
                    ).littleEndian
                )
            }
        } ?? []
    }

    private let meshExpectedBase64 =
        ""
    private let conditionExpectedBase64 =
        ""
}
